function wsGenerateLevel(levelIndex) {
  const level = WS_LEVELS[levelIndex];
  const lockOf = new Map((level.l || []).map(e => [e.i, e.c]));
  return level.b.map((colorIdxs, i) => {
    const isLocked = lockOf.has(i);
    const fogMask = (level.f && level.f[i]) || 0;
    const units = colorIdxs.map((ci, u) => ({
      c: WS_COLORS[ci],
      h: !isLocked && !!(fogMask & (1 << u)),
    }));
    if (!isLocked && units.length) units[units.length - 1].h = false; // defensive: top always visible
    return { units, locked: isLocked, unlockColor: isLocked ? WS_COLORS[lockOf.get(i)] : null };
  });
}

/* ── core pour rules — operate on bottle objects {units, locked, unlockColor} ── */
function wsTopRun(bottle) {
  const units = bottle.units;
  if (!units.length) return { color: null, len: 0 };
  const color = units[units.length - 1].c;
  let len = 1;
  while (len < units.length && units[units.length - 1 - len].c === color) len++;
  return { color, len };
}
function wsCanPour(bottles, from, to) {
  if (from === to) return false;
  const src = bottles[from], dst = bottles[to];
  if (!src || !dst || src.locked || dst.locked) return false;
  if (!src.units.length || dst.units.length >= WS_CAPACITY) return false;
  const top = src.units[src.units.length - 1].c;
  return dst.units.length === 0 || dst.units[dst.units.length - 1].c === top;
}
function wsPour(bottles, from, to) {
  if (!wsCanPour(bottles, from, to)) return 0;
  const { len } = wsTopRun(bottles[from]);
  const amt = Math.min(len, WS_CAPACITY - bottles[to].units.length);
  for (let i = 0; i < amt; i++) bottles[to].units.push(bottles[from].units.pop());
  return amt;
}
function wsIsSolved(bottles) {
  return bottles.every(b => {
    if (b.locked) return false;
    return b.units.length === 0 ||
      (b.units.length === WS_CAPACITY && b.units.every(u => u.c === b.units[0].c));
  });
}

// "Top is always visible" invariant restorer — call after any mutation
// (pour, extra bottle added, level start, unlock) so a covered-then-
// re-exposed unit is never silently hidden again.
function wsRevealTops(bottles) {
  for (const b of bottles) {
    if (b.locked || !b.units.length) continue;
    const top = b.units[b.units.length - 1];
    if (top.h) top.h = false;
  }
}

// Unlocks a locked bottle the moment some OTHER, non-locked bottle is full
// and monochrome in that lock's required color. The triggering bottle is
// left untouched — it stays a normal completed bottle, the locked one just
// becomes a second, independent, now-interactive bottle.
function wsCheckUnlocks(bottles) {
  let changed = false;
  for (const b of bottles) {
    if (!b.locked) continue;
    const available = bottles.some(o =>
      o !== b && !o.locked && o.units.length === WS_CAPACITY &&
      o.units.every(u => u.c === b.unlockColor));
    if (available) { b.locked = false; changed = true; }
  }
  if (changed) wsRevealTops(bottles);
  return changed;
}

// "Bottle done" = would count as solved on its own (empty, or full +
// monochrome) — mirrors the per-bottle check already inline in wsIsSolved.
function wsBottleIsDone(bottle) {
  if (bottle.locked) return false;
  return bottle.units.length === 0 ||
    (bottle.units.length === WS_CAPACITY && bottle.units.every(u => u.c === bottle.units[0].c));
}

/* ══════════════════════════════════════════════════════════
   GAME FLOW — reads/writes G.waterSort
══════════════════════════════════════════════════════════ */
// Transient, purely-visual hints for wsRender() — never persisted in G,
// since they're meaningless (and would just be stale) after a reload.
let wsLastPourAnim = null;       // { from, to, amt } | null
let wsCelebratedBottles = new Set(); // bottle indices that already played their one-shot done-pulse this level

function wsOnBottleTap(idx) {
  const ws = G.waterSort;
  const bottle = ws.bottles[idx];
  if (!bottle || bottle.locked) return; // locked bottles are fully inert
  if (ws.selectedBottle === null) {
    if (bottle.units.length) { ws.selectedBottle = idx; wsRender(); }
    return;
  }
  if (ws.selectedBottle === idx) { ws.selectedBottle = null; wsRender(); return; }
  const fromIdx = ws.selectedBottle;
  const amt = wsPour(ws.bottles, fromIdx, idx);
  ws.selectedBottle = null;
  if (amt > 0) {
    wsLastPourAnim = { from: fromIdx, to: idx, amt };
    wsRevealTops(ws.bottles);
    wsCheckUnlocks(ws.bottles);
    saveState(); // explicit — mid-level progress must survive a reload
    if (wsIsSolved(ws.bottles)) { wsOnLevelSolved(); return; }
  }
  wsRender();
}
window.wsOnBottleTap = wsOnBottleTap;

function wsOnLevelSolved() {
  G.stats.waterSortLevelsCompleted = (G.stats.waterSortLevelsCompleted || 0) + 1;
  checkTrophies();
  showToast("🧪 Level gelöst!");
  saveState();
  wsRender();
  setTimeout(wsAdvanceToNextLevel, 900);
}

function wsAdvanceToNextLevel() {
  const ws = G.waterSort;
  ws.playOrderPos++;
  if (ws.playOrderPos >= ws.playOrder.length) {
    const prevLast = ws.playOrder[ws.playOrder.length - 1];
    const order = shuffleArray([...Array(WS_LEVEL_COUNT).keys()]);
    if (order[0] === prevLast) [order[0], order[1]] = [order[1], order[0]];
    ws.playOrder = order;
    ws.playOrderPos = 0;
  }
  wsStartLevel(ws.playOrder[ws.playOrderPos]);
}

function wsStartLevel(levelIndex) {
  const ws = G.waterSort;
  ws.currentLevelIndex = levelIndex;
  ws.bottles = wsGenerateLevel(levelIndex);
  wsRevealTops(ws.bottles);
  ws.extraBottlesUsed = 0;
  ws.selectedBottle = null;
  wsLastPourAnim = null;
  wsCelebratedBottles = new Set();
  saveState();
  wsRender();
}

function wsRestartLevel() {
  const ws = G.waterSort;
  if (ws.currentLevelIndex == null) return;
  wsStartLevel(ws.currentLevelIndex);
  showToast("🔄 Level neu gestartet.");
}
window.wsRestartLevel = wsRestartLevel;

function wsEnsureQueueAndLevel() {
  const ws = G.waterSort;
  if (!ws.playOrder.length) {
    ws.playOrder = shuffleArray([...Array(WS_LEVEL_COUNT).keys()]);
    ws.playOrderPos = 0;
  }
  if (ws.currentLevelIndex == null || !ws.bottles.length) {
    wsStartLevel(ws.playOrder[ws.playOrderPos]);
  } else {
    wsRender();
  }
}
window.wsEnsureQueueAndLevel = wsEnsureQueueAndLevel;

function wsBuyExtraBottle() {
  const ws = G.waterSort;
  if (ws.extraBottlesUsed >= WS_MAX_EXTRA_BOTTLES) {
    showToast(`Maximal ${WS_MAX_EXTRA_BOTTLES} Extra-Fläschchen pro Level!`);
    return;
  }
  if (!hasActiveQuestions()) {
    showToast("Keine aktiven Fragen! Aktiviere Kapitel unter 📚.");
    return;
  }
  askQuestions("🧪 Extra-Fläschchen", 1, () => {
    ws.bottles.push({ units: [], locked: false, unlockColor: null });
    wsRevealTops(ws.bottles);
    ws.extraBottlesUsed++;
    G.stats.waterSortExtraBottlesBought = (G.stats.waterSortExtraBottlesBought || 0) + 1;
    checkTrophies();
    saveState();
    wsRender();
    showToast("🧪 Neues Fläschchen erhalten!");
  }, null);
}
window.wsBuyExtraBottle = wsBuyExtraBottle;

/* ══════════════════════════════════════════════════════════
   RENDERING
══════════════════════════════════════════════════════════ */
function wsRender() {
  const ws = G.waterSort;
  const infoEl = document.getElementById("ws-level-info");
  const gridEl = document.getElementById("ws-bottle-grid");
  const buyBtn = document.getElementById("ws-buy-bottle-btn");
  if (!gridEl) return;

  if (infoEl) {
    infoEl.textContent = ws.currentLevelIndex == null
      ? ""
      : `Level ${ws.currentLevelIndex + 1} / ${WS_LEVEL_COUNT}`;
  }

  const pourAnim = wsLastPourAnim;
  wsLastPourAnim = null; // consume — a later, unrelated render must not replay it

  gridEl.innerHTML = (ws.bottles || []).map((bottle, idx) => {
    if (bottle.locked) {
      return `<div class="ws-bottle ws-bottle--locked" data-idx="${idx}">
        <div class="ws-bottle-stack ws-bottle-stack--locked">
          <div class="ws-lock-cover"><div class="ws-lock-dot" style="background:${bottle.unlockColor}"></div></div>
        </div>
      </div>`;
    }
    const incomingFrom = pourAnim && pourAnim.to === idx ? bottle.units.length - pourAnim.amt : Infinity;
    const slots = [];
    for (let i = 0; i < WS_CAPACITY; i++) {
      const unit = bottle.units[i];
      if (!unit) { slots.push(`<div class="ws-segment ws-segment--empty"></div>`); continue; }
      const incoming = i >= incomingFrom;
      const incomingCls = incoming ? ' ws-segment--incoming' : '';
      const delayStyle = incoming ? `animation-delay:${(i - incomingFrom) * 60}ms;` : '';
      if (unit.h) slots.push(`<div class="ws-segment ws-segment--fog${incomingCls}" style="${delayStyle}"></div>`);
      else slots.push(`<div class="ws-segment${incomingCls}" style="background:${unit.c};${delayStyle}"></div>`);
    }
    let cls = "ws-bottle";
    if (ws.selectedBottle === idx) cls += " ws-bottle--selected";
    if (pourAnim && pourAnim.from === idx) cls += " ws-bottle--pouring";
    const done = wsBottleIsDone(bottle);
    if (done) {
      cls += " ws-bottle--complete";
      if (!wsCelebratedBottles.has(idx)) {
        cls += " ws-bottle--complete-pulse";
        wsCelebratedBottles.add(idx);
      }
    }
    return `<div class="${cls}" data-idx="${idx}">
      <div class="ws-bottle-stack">${slots.join("")}</div>
    </div>`;
  }).join("");

  gridEl.querySelectorAll(".ws-bottle").forEach(el => {
    el.onclick = () => wsOnBottleTap(parseInt(el.dataset.idx, 10));
  });

  if (buyBtn) {
    const atCap = (ws.extraBottlesUsed || 0) >= WS_MAX_EXTRA_BOTTLES;
    buyBtn.disabled = atCap;
    buyBtn.classList.toggle("ws-buy-bottle-btn--off", atCap);
    buyBtn.textContent = atCap
      ? "➕ Maximal erreicht"
      : `➕ Extra-Fläschchen (1 Frage) · ${ws.extraBottlesUsed || 0}/${WS_MAX_EXTRA_BOTTLES}`;
  }
}
window.wsRender = wsRender;
